import{_ as t,o as a,c as o,a4 as s}from"./chunks/framework.DJn0YgWS.js";const u=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),i={name:"guide/faq.md"};function n(r,e,d,c,l,h){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Common questions about Specialist Agent.</p><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><h3 id="can-i-use-it-without-a-framework-pack" tabindex="-1">Can I use it without a framework pack? <a class="header-anchor" href="#can-i-use-it-without-a-framework-pack" aria-label="Permalink to &quot;Can I use it without a framework pack?&quot;">​</a></h3><p>Yes. The 9 framework-agnostic agents (<code>@starter</code>, <code>@explorer</code>, <code>@finance</code>, <code>@cloud</code>, <code>@security</code>, <code>@designer</code>, <code>@data</code>, <code>@devops</code>, <code>@tester</code>) work independently of any pack. They don&#39;t require <code>ARCHITECTURE.md</code> or pack-specific files.</p><p>The pack-specific agents (<code>@builder</code>, <code>@reviewer</code>, <code>@doctor</code>, <code>@migrator</code>) require a framework pack because they rely on <code>ARCHITECTURE.md</code> for code generation patterns.</p><h3 id="does-it-work-with-existing-projects" tabindex="-1">Does it work with existing projects? <a class="header-anchor" href="#does-it-work-with-existing-projects" aria-label="Permalink to &quot;Does it work with existing projects?&quot;">​</a></h3><p>Yes. Run <code>npx specialist-agent init</code> in your project root and choose your framework pack. The installer only adds markdown files — it doesn&#39;t modify your source code, dependencies, or configuration.</p><p>Use <code>@explorer</code> to assess an existing codebase before making changes:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Use @explorer to assess this project&#39;s architecture and health&quot;</span></span></code></pre></div><h3 id="how-does-it-work-with-monorepos" tabindex="-1">How does it work with monorepos? <a class="header-anchor" href="#how-does-it-work-with-monorepos" aria-label="Permalink to &quot;How does it work with monorepos?&quot;">​</a></h3><p>Each workspace can have its own <code>ARCHITECTURE.md</code> and <code>CLAUDE.md</code>. When you open Claude Code in a specific workspace directory, agents read that workspace&#39;s configuration.</p><p>For shared patterns across workspaces, keep a root-level <code>ARCHITECTURE.md</code> with common rules, and workspace-level files for overrides.</p><h3 id="does-it-work-offline" tabindex="-1">Does it work offline? <a class="header-anchor" href="#does-it-work-offline" aria-label="Permalink to &quot;Does it work offline?&quot;">​</a></h3><p>No. Specialist Agent requires an active connection to the Claude API. The agents and skills are markdown instructions that Claude Code reads and executes — the intelligence comes from the Claude model, not from local code.</p><h3 id="how-do-i-update-specialist-agent" tabindex="-1">How do I update Specialist Agent? <a class="header-anchor" href="#how-do-i-update-specialist-agent" aria-label="Permalink to &quot;How do I update Specialist Agent?&quot;">​</a></h3><p>Run the installer again:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> specialist-agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>It overwrites the agent and skill files with the latest versions. Your <code>ARCHITECTURE.md</code> customizations are preserved since they live in a separate file.</p><h2 id="agents" tabindex="-1">Agents <a class="header-anchor" href="#agents" aria-label="Permalink to &quot;Agents&quot;">​</a></h2><h3 id="what-s-the-difference-between-full-and-lite-agents" tabindex="-1">What&#39;s the difference between Full and Lite agents? <a class="header-anchor" href="#what-s-the-difference-between-full-and-lite-agents" aria-label="Permalink to &quot;What&#39;s the difference between Full and Lite agents?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Full Agents</th><th>Lite Agents</th></tr></thead><tbody><tr><td>Model</td><td>Sonnet/Opus</td><td>Haiku</td></tr><tr><td>Cost</td><td>Higher per token</td><td>~50% cheaper</td></tr><tr><td>Quality</td><td>Better for complex tasks</td><td>Good for simple tasks</td></tr><tr><td>Speed</td><td>Slower</td><td>Faster</td></tr><tr><td>Best for</td><td>New modules, PR reviews, migrations</td><td>Prototyping, simple scaffolds, iteration</td></tr></tbody></table><p>Use Lite agents when speed matters more than polish. Use Full agents when accuracy is critical (PR reviews, migrations, bug investigations).</p><h3 id="can-i-create-my-own-agents" tabindex="-1">Can I create my own agents? <a class="header-anchor" href="#can-i-create-my-own-agents" aria-label="Permalink to &quot;Can I create my own agents?&quot;">​</a></h3><p>Yes. See <a href="/specialist-agent/pr-preview/pr-45/customization/creating-agents.html">Creating Agents</a> for a step-by-step guide. Custom agents follow the same 5-part blueprint:</p><ol><li><strong>Mission</strong> — What the agent does</li><li><strong>Workflow</strong> — Step-by-step process</li><li><strong>Output</strong> — Structured result format</li><li><strong>Rules</strong> — Hard constraints</li><li><strong>Handoff Protocol</strong> — When to suggest other agents</li></ol><h3 id="how-do-agents-know-my-project-s-conventions" tabindex="-1">How do agents know my project&#39;s conventions? <a class="header-anchor" href="#how-do-agents-know-my-project-s-conventions" aria-label="Permalink to &quot;How do agents know my project&#39;s conventions?&quot;">​</a></h3><p>All agents read <code>docs/ARCHITECTURE.md</code> before acting. This file defines your naming conventions, directory structure, layer rules, and code patterns. When you edit it, every agent&#39;s behavior changes immediately.</p><h3 id="can-i-use-agents-from-different-packs" tabindex="-1">Can I use agents from different packs? <a class="header-anchor" href="#can-i-use-agents-from-different-packs" aria-label="Permalink to &quot;Can I use agents from different packs?&quot;">​</a></h3><p>Each project should use one framework pack. The pack-specific agents (<code>@builder</code>, <code>@reviewer</code>, <code>@doctor</code>, <code>@migrator</code>) are tailored to a specific framework&#39;s patterns. Using React agents in a Vue project would generate incorrect code.</p><p>The framework-agnostic agents work with any pack.</p><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><h3 id="how-much-does-it-cost-to-use" tabindex="-1">How much does it cost to use? <a class="header-anchor" href="#how-much-does-it-cost-to-use" aria-label="Permalink to &quot;How much does it cost to use?&quot;">​</a></h3><p>Costs depend on the Claude model and number of tokens consumed. See <a href="/specialist-agent/pr-preview/pr-45/reference/tokens.html">Token Usage</a> for detailed estimates per operation, including real-world scenarios.</p><p><strong>Quick reference:</strong></p><ul><li>Single component scaffold: ~3-5k tokens</li><li>Full module with tests: ~40-60k tokens</li><li>Module migration: ~50-120k tokens</li></ul><h3 id="how-can-i-reduce-costs" tabindex="-1">How can I reduce costs? <a class="header-anchor" href="#how-can-i-reduce-costs" aria-label="Permalink to &quot;How can I reduce costs?&quot;">​</a></h3><ol><li>Use <strong>Lite agents</strong> for rapid iteration</li><li>Use <strong>skills</strong> instead of agents for focused tasks (cheaper)</li><li>Migrate <strong>incrementally</strong> (one component at a time)</li><li>Run automated checks before full reviews</li></ol><p>See <a href="/specialist-agent/pr-preview/pr-45/reference/tokens.html#tips-to-reduce-token-usage">Tips to Reduce Token Usage</a> for more strategies.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="agents-are-not-following-my-architecture-md" tabindex="-1">Agents are not following my ARCHITECTURE.md <a class="header-anchor" href="#agents-are-not-following-my-architecture-md" aria-label="Permalink to &quot;Agents are not following my ARCHITECTURE.md&quot;">​</a></h3><ol><li>Verify the file is at <code>docs/ARCHITECTURE.md</code> (not the project root)</li><li>Check for syntax errors in the markdown</li><li>Run <code>/review-check-architecture</code> to validate</li><li>Ensure your rules are explicit — agents follow what&#39;s written literally</li></ol><h3 id="skills-return-command-not-found" tabindex="-1">Skills return &quot;command not found&quot; <a class="header-anchor" href="#skills-return-command-not-found" aria-label="Permalink to &quot;Skills return &quot;command not found&quot;&quot;">​</a></h3><p>Skills are not shell commands. They&#39;re instructions for Claude Code. Use them inside Claude Code&#39;s chat interface:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Correct — inside Claude Code</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/dev-create-component</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ProductCard</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Wrong — in a terminal</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> specialist-agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev-create-component</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ProductCard</span></span></code></pre></div><h3 id="generated-code-doesn-t-match-my-stack" tabindex="-1">Generated code doesn&#39;t match my stack <a class="header-anchor" href="#generated-code-doesn-t-match-my-stack" aria-label="Permalink to &quot;Generated code doesn&#39;t match my stack&quot;">​</a></h3><p>Your <code>ARCHITECTURE.md</code> may not reflect your actual stack. Common fixes:</p><ol><li>Update the API client section if you use Axios instead of fetch</li><li>Update the state management section if you use a different store library</li><li>Update the directory structure if your project uses a non-standard layout</li></ol><p>See <a href="/specialist-agent/pr-preview/pr-45/customization/editing-patterns.html">Editing Patterns</a> for examples of common customizations.</p>`,49)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
